entry.codeblock:
always-write-option-82  (circuit-id | remote-id);
relay-source;
trust-option-82;
user-defined-option-82 string

conbody.codeblock:
[edit]
forwarding-options { 
    dhcp-relay {  
        active-server-group name; 
        duplicate-clients-in-subnet (incoming-interface | option-82); 
        forward-only;
        overrides {
            always-write-option-82  (circuit-id | remote-id); 
            relay-source;
            trust-option-82;
            user-defined-option-82 string
        }
        relay-option-82 { 
            circuit-id { 
                prefix { 
                    host-name; 
                    logical-system-name; 
                    routing-instance-name; 
                } 
                use-interface-description (device | logical); 
                user-defined; 
            } 
            remote-id { 
                prefix { 
                    host-name; 
                    logical-system-name; 
                    routing-instance-name; 
                } 
                use-interface-description (device | logical); 
            } 
        } 
        server-group name { 
            ip-address; 
        } 
        group name { 
            relay-option-82 {
                circuit-id { 
                    prefix { 
                        host-name; 
                        logical-system-name; 
                        routing-instance-name; 
                    } 
                    use-interface-description (device | logical); 
                    user-defined; 
                } 
                remote-id { 
                    prefix { 
                        host-name; 
                        logical-system-name; 
                        routing-instance-name; 
                    } 
                    use-interface-description (device | logical); 
                } 
            }   
            active-server-group name; 
            interface interface_name; 
        } 
    } 
}

[edit]
forwarding-options { 
    dhcp-relay { 
        dhcpv6 { 
            active-server-group name; 
            forward-only; 
            relay-agent-interface-id { 
                prefix { 
                    host-name; 
                    logical-system-name; 
                    routing-instance-name; 
                } 
                use-interface-description (device | logical); 
            } 
            relay-agent-remote-id { 
                prefix { 
                    host-name; 
                    logical-system-name; 
                    routing-instance-name; 
                } 
                use-interface-description (device | logical); 
            } 
            server-group <name> { 
                ip-address; 
            } 
            group name { 
                relay-agent-interface-id { 
                    prefix { 
                        host-name; 
                        logical-system-name; 
                        routing-instance-name; 
                    } 
                    use-interface-description (device | logical); 
                } 
                relay-agent-remote-id { 
                    prefix { 
                        host-name; 
                        logical-system-name; 
                        routing-instance-name; 
                    } 
                    use-interface-description (device | logical); 
                }
                active-server-group name; 
                interface interface_name;              
            } 
        } 
    } 
}

[edit]
system {
    processes {
        dhcp-service {
            traceoptions {
                file jdhcpd size 20m;
                level all;
                flag all;
            }
        }
    }
}
